import{_ as t,o,c as i,ag as a}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"First Flight Guide","description":"","frontmatter":{},"headers":[],"relativePath":"ko/qgc-user-guide/getting_started/quick_start.md","filePath":"ko/qgc-user-guide/getting_started/quick_start.md"}'),n={name:"ko/qgc-user-guide/getting_started/quick_start.md"};function l(r,e,s,c,h,d){return o(),i("div",null,e[0]||(e[0]=[a('<h1 id="first-flight-guide" tabindex="-1">First Flight Guide <a class="header-anchor" href="#first-flight-guide" aria-label="Permalink to &quot;First Flight Guide&quot;">​</a></h1><p>This guide walks you through connecting your vehicle, verifying it&#39;s ready, and executing your first flight.</p><h2 id="_1-connect-your-vehicle" tabindex="-1">1. Connect Your Vehicle <a class="header-anchor" href="#_1-connect-your-vehicle" aria-label="Permalink to &quot;1. Connect Your Vehicle&quot;">​</a></h2><p>Start <em>QGroundControl</em>, then connect your vehicle using one of these methods:</p><ul><li><strong>USB</strong> — plug the flight controller directly into your computer</li><li><strong>Telemetry radio</strong> — connect a ground-side radio module via USB</li><li><strong>WiFi / Ethernet</strong> — connect to the vehicle&#39;s network (common for companion computers and some commercial drones)</li></ul><p>QGC auto-detects most connections. If your vehicle doesn&#39;t appear, check <strong>Application Settings &gt; Comm Links</strong> to verify settings or create a manual link.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Make sure QGC has an internet connection when you connect a new vehicle so the map loads correctly.</p></div><h2 id="_2-check-vehicle-status" tabindex="-1">2. Check Vehicle Status <a class="header-anchor" href="#_2-check-vehicle-status" aria-label="Permalink to &quot;2. Check Vehicle Status&quot;">​</a></h2><p>Once connected, look at the <strong>toolbar indicators</strong> across the top of the screen. Each icon shows a subsystem status — tap any indicator for details:</p><ul><li><strong>GPS</strong> — satellite count and fix type (3D fix required for most flight modes)</li><li><strong>Battery</strong> — voltage and remaining capacity</li><li><strong>RC</strong> — transmitter connection status</li><li><strong>Telemetry</strong> — link signal quality</li><li><strong>Flight Mode</strong> — current mode (tap to change)</li><li><strong>Armed/Disarmed</strong> — arming state (tap to arm/disarm)</li></ul><h2 id="_3-calibrate-new-vehicles" tabindex="-1">3. Calibrate (New Vehicles) <a class="header-anchor" href="#_3-calibrate-new-vehicles" aria-label="Permalink to &quot;3. Calibrate (New Vehicles)&quot;">​</a></h2><p>For a new vehicle, QGC opens <a href="./../setup_view/setup_view.html">Vehicle Configuration</a> automatically. Complete these steps in order:</p><ol><li><strong><a href="./../setup_view/firmware.html">Firmware</a></strong> — install or update flight controller firmware (USB only)</li><li><strong>Airframe / Frame</strong> — select your vehicle type and frame layout</li><li><strong>Sensors</strong> — calibrate compass, accelerometer, gyroscope, and (if equipped) level horizon</li><li><strong>Radio</strong> — calibrate your RC transmitter stick ranges</li><li><strong>Flight Modes</strong> — assign flight modes to transmitter switches</li><li><strong>Power</strong> — configure battery cell count and voltage sensing</li></ol><p>Parameters and other settings can be adjusted later. See the <a href="./../setup_view/sensors_px4.html">PX4</a> or <a href="./../setup_view/sensors_ardupilot.html">ArduPilot</a> sensor pages for firmware-specific guidance.</p><h2 id="_4-plan-a-simple-mission-optional" tabindex="-1">4. Plan a Simple Mission (Optional) <a class="header-anchor" href="#_4-plan-a-simple-mission-optional" aria-label="Permalink to &quot;4. Plan a Simple Mission (Optional)&quot;">​</a></h2><p>Open the <strong>Planning Missions</strong> view to create a basic waypoint mission:</p><ol><li>Tap the map to place a takeoff point</li><li>Tap additional locations to add waypoints</li><li>Set the desired altitude for each waypoint (or accept the default)</li><li>Upload the mission to the vehicle</li></ol><p>See <a href="./../plan_view/plan_view.html">Planning Missions</a> for details on surveys, geofences, and rally points.</p><h2 id="_5-fly" tabindex="-1">5. Fly <a class="header-anchor" href="#_5-fly" aria-label="Permalink to &quot;5. Fly&quot;">​</a></h2><p>Switch to the <strong>Flying</strong> view. You should see a map centered on your vehicle&#39;s GPS position with the HUD overlay showing attitude.</p><p><strong>To fly a mission:</strong></p><ol><li>Confirm all toolbar indicators are green/nominal</li><li>Slide to arm (or tap the arm indicator)</li><li>Tap <strong>Start Mission</strong> — the vehicle will take off and follow the planned route</li><li>Monitor progress in the toolbar and map</li><li>When the mission completes, the vehicle returns to launch and lands automatically (depending on firmware settings)</li></ol><p><strong>To fly manually:</strong></p><ol><li>Arm the vehicle via QGC or your transmitter</li><li>Take off using your transmitter</li><li>Use the <strong>Fly Tools</strong> (left edge of the map) for guided actions: Return to Launch, Land, Pause, Change Altitude, Go To Location, Orbit</li></ol><h2 id="_6-after-landing" tabindex="-1">6) After Landing <a class="header-anchor" href="#_6-after-landing" aria-label="Permalink to &quot;6) After Landing&quot;">​</a></h2><ul><li><strong>Review telemetry</strong> — open <a href="./../analyze_view/">Analysis &amp; Logs</a> to download and inspect flight logs</li><li><strong>Download logs</strong> — use <a href="./../analyze_view/log_download.html">Log Download</a> to pull logs from the vehicle for post-flight analysis</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li>Vehicle not connecting? See <a href="./../troubleshooting/vehicle_connection.html">Connection Problems</a></li><li>Parameters won&#39;t download? See <a href="./../troubleshooting/parameter_download.html">Parameter Download Failures</a></li><li>Mission won&#39;t upload? See <a href="./../troubleshooting/plan_upload_download.html">Plan Upload/Download Failures</a></li></ul>',28)]))}const p=t(n,[["render",l]]);export{u as __pageData,p as default};
